import { useState } from 'react';
import { ModeSelector } from './ModeSelector';
import { SizeGrid } from './SizeGrid';
import { useGameActions } from '../../state/store';
import { dailyDifficulty } from '../../engine';
import type { EtchMode, EtchSize } from '../../engine';
import '../../features/onboarding/onboarding.css';
import './mode.css';

// Picks an approximate dim for the board skeleton so it matches what will
// appear after generation. O(1).
function dimsForSkeleton(mode: EtchMode, size: EtchSize): 5 | 10 {
  if (mode === 'daily') return 10;
  return size === 'sketch' ? 5 : 10;
}

export function NewGameSheet() {
  const a = useGameActions();
  const [mode, setMode] = useState<EtchMode>('daily');
  const [size, setSize] = useState<EtchSize>('beginner');
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showSlowHint, setShowSlowHint] = useState(false);

  async function start(forceMode?: EtchMode, forceSize?: EtchSize) {
    setBusy(true);
    setError(null);
    setShowSlowHint(false);
    const slowTimer = setTimeout(() => setShowSlowHint(true), 1500);
    try {
      const m = forceMode ?? mode;
      const sz = forceSize ?? size;
      await a.newGame({ mode: m, size: sz });
    } catch {
      const effectiveSize = forceSize ?? size;
      setError(`Couldn't find a deductive ${effectiveSize} puzzle this round.`);
    } finally {
      clearTimeout(slowTimer);
      setBusy(false);
    }
  }

  return (
    <div className="etch-newgame-sheet" data-slot="mode" role="region" aria-label="Pick a puzzle">
      <div className="etch-newgame-card">
        <h2>Pick a puzzle</h2>
        <ModeSelector mode={mode} onChange={m => { setMode(m); setError(null); }} />
        {mode === 'free' && <SizeGrid size={size} onChange={setSize} />}
        {mode === 'daily' && (
          <p className="etch-newgame-daily-info">
            Today's daily: <strong style={{ textTransform: 'capitalize' }}>{dailyDifficulty(new Date())}</strong>.
          </p>
        )}
        <button
          className="etch-newgame-start"
          disabled={busy}
          onClick={() => void start()}
          aria-label={mode === 'daily' ? "Play today's puzzle" : `Start a ${size} puzzle`}
          data-testid="newgame-start"
        >
          {busy ? 'Loading…' : (mode === 'daily' ? "Play today's puzzle" : 'Start')}
        </button>
        {busy && (
          <div
            className="etch-board-skeleton"
            data-rows={dimsForSkeleton(mode, size)}
            data-testid="newgame-skeleton"
            aria-hidden="true"
          >
            {Array.from({ length: dimsForSkeleton(mode, size) ** 2 }, (_, i) => (
              <div key={i} className="etch-skeleton etch-board-skel-cell" />
            ))}
          </div>
        )}
        {showSlowHint && busy && (
          <p className="etch-newgame-slow-hint">This may take a few seconds…</p>
        )}
        {error && (
          <div className="etch-newgame-error" role="alert">
            <p>{error}</p>
            <button onClick={() => void start()}>Try again</button>
          </div>
        )}
        {mode === 'free' && (
          <button
            className="etch-newgame-cross"
            onClick={() => { setMode('daily'); void start('daily'); }}
          >
            or try today's puzzle
          </button>
        )}
        {mode === 'daily' && (
          <button className="etch-newgame-cross" onClick={() => setMode('free')}>
            or pick a size
          </button>
        )}
      </div>
    </div>
  );
}
