import type { EtchMode } from '../../engine';

export function ModeSelector({ mode, onChange }: { mode: EtchMode; onChange: (m: EtchMode) => void }) {
  return (
    <div className="etch-mode-pills" role="tablist" aria-label="Game mode">
      {(['daily', 'free'] as EtchMode[]).map(m => (
        <button
          key={m}
          role="tab"
          aria-selected={mode === m}
          className="etch-mode-pill"
          data-active={mode === m || undefined}
          onClick={() => onChange(m)}
        >
          {m === 'daily' ? "Today's puzzle" : 'Pick a size'}
        </button>
      ))}
    </div>
  );
}
